firmware_template.source:
#include "ds18b20.h"
#include <OneWire.h>
#include <DallasTemperature.h>
#define OW_PIN 4
static OneWire ow(OW_PIN);
static DallasTemperature dt(&ow);
static float _t=0;static int _cnt=0;
static unsigned long _last=0;
void ds18b20_setup(){dt.begin();_cnt=dt.getDeviceCount();Serial.printf("[ds18b20] OK %d sensors\n",_cnt);}
void ds18b20_loop(){if(millis()-_last<1000)return;_last=millis();dt.requestTemperatures();_t=dt.getTempCByIndex(0);}
float ds18b20_get_temperature(){return _t;}
int ds18b20_get_count(){return _cnt;}
